import { ObjectAssertion } from './assert.mjs';
export const VOID_CONTENT = [];
export class NodeAssertion {
    contentRule;
    validateData;
    constructor(contentRule, validateData){
        this.contentRule = contentRule;
        this.validateData = validateData;
    }
    assert(node, path) {
        const $ = new ObjectAssertion(node, path);
        if (!$.object()) {
            return $.errors;
        }
        $.noAdditionalProperties([
            'nodeType',
            'data',
            'content'
        ]);
        const { nodeTypes, min = 0 } = Array.isArray(this.contentRule) ? {
            nodeTypes: this.contentRule
        } : this.contentRule(node, path);
        if (nodeTypes.length === 0 && min > 0) {
            throw new Error(`Invalid content rule. Cannot have enforce a 'min' of ${min} with no nodeTypes`);
        }
        $.minLength('content', min);
        if (nodeTypes.length === 0) {
            $.empty('content');
        } else {
            $.each('content', (item, path)=>{
                const item$ = new ObjectAssertion(item, path);
                if (!item$.object()) {
                    return item$.errors;
                }
                item$.enum('nodeType', nodeTypes);
                return item$.errors;
            });
        }
        if ($.object('data')) {
            const dataErrors = this.validateData?.(node.data, path.of('data')) ?? [];
            $.catch(...dataErrors);
        }
        return $.errors;
    }
}
export class EntityLinkAssertion extends NodeAssertion {
    linkType;
    type;
    constructor(linkType, contentNodeTypes){
        super(contentNodeTypes, (data, path)=>this.assertLink(data, path)), this.linkType = linkType;
        this.type = this.linkType.startsWith('Contentful:') ? 'ResourceLink' : 'Link';
    }
    assertLink = (data, path)=>{
        const $ = new ObjectAssertion(data, path);
        if ($.object('target')) {
            const sys$ = new ObjectAssertion(data.target.sys, path.of('target').of('sys'));
            if (sys$.object()) {
                sys$.enum('type', [
                    this.type
                ]);
                sys$.enum('linkType', [
                    this.linkType
                ]);
                if (this.type === 'Link') {
                    sys$.string('id');
                    sys$.noAdditionalProperties([
                        'type',
                        'linkType',
                        'id'
                    ]);
                } else if (this.type === 'ResourceLink') {
                    sys$.string('urn');
                    sys$.noAdditionalProperties([
                        'type',
                        'linkType',
                        'urn'
                    ]);
                }
            }
            $.catch(...sys$.errors);
        }
        $.noAdditionalProperties([
            'target'
        ]);
        return $.errors;
    };
}
export class HyperLinkAssertion extends NodeAssertion {
    constructor(){
        super([
            'text'
        ], (data, path)=>this.assertLink(data, path));
    }
    assertLink = (data, path)=>{
        const $ = new ObjectAssertion(data, path);
        $.string('uri');
        $.noAdditionalProperties([
            'uri'
        ]);
        return $.errors;
    };
}
export const assert = (contentRule, validateData)=>{
    return new NodeAssertion(contentRule, validateData);
};
export const assertLink = (linkType, contentRule)=>{
    return new EntityLinkAssertion(linkType, contentRule);
};
